DELIMITER $$
--
-- Procedures
--
DROP PROCEDURE IF EXISTS `sp_gen`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_gen` (IN `sid` INT UNSIGNED)   BEGIN
  DECLARE done        INT DEFAULT 0;
  DECLARE tpl_id      INT UNSIGNED;
  DECLARE cat_name    VARCHAR(100);
  DECLARE cat_price   DECIMAL(8,2);
  DECLARE row_csv     VARCHAR(200);
  DECLARE seats_per   TINYINT;
  DECLARE is_split    TINYINT(1);
  DECLARE sort_ord    TINYINT;
  DECLARE cid         INT UNSIGNED;
  DECLARE row_label   VARCHAR(10);
  DECLARE seat_n      INT;
  DECLARE comma_pos   INT;
  DECLARE remaining   VARCHAR(200);

  DECLARE tpl_cursor CURSOR FOR
    SELECT id, category_name, price, `rows`, seats_per_row, box_split, sort_order
    FROM seat_type_templates
    ORDER BY sort_order, id;

  DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

  OPEN tpl_cursor;

  tpl_loop: LOOP
    FETCH tpl_cursor INTO tpl_id, cat_name, cat_price, row_csv, seats_per, is_split, sort_ord;
    IF done THEN LEAVE tpl_loop; END IF;

    -- Insert category for this show
    VALUES (sid, cat_name, cat_price);
    SET cid = LAST_INSERT_ID();

    -- Walk each comma-separated row label
    SET remaining = TRIM(row_csv);
    WHILE LENGTH(remaining) > 0 DO
      SET comma_pos = LOCATE(',', remaining);
      IF comma_pos > 0 THEN
        SET row_label = TRIM(SUBSTRING(remaining, 1, comma_pos - 1));
        SET remaining = TRIM(SUBSTRING(remaining, comma_pos + 1));
      ELSE
        SET row_label = TRIM(remaining);
        SET remaining = '';
      END IF;

      IF LENGTH(row_label) > 0 THEN
        IF is_split THEN
          -- Box split: left block 1-7, gap at 8, right block 9-14
          SET seat_n = 1;
          WHILE seat_n <= 7 DO
            VALUES (sid, cid, row_label, seat_n, 'available');
            SET seat_n = seat_n + 1;
          END WHILE;
          SET seat_n = 9;
          WHILE seat_n <= 14 DO
            VALUES (sid, cid, row_label, seat_n, 'available');
            SET seat_n = seat_n + 1;
          END WHILE;
        ELSE
          -- Standard layout: seats 1..seats_per_row
          SET seat_n = 1;
          WHILE seat_n <= seats_per DO
            VALUES (sid, cid, row_label, seat_n, 'available');
            SET seat_n = seat_n + 1;
          END WHILE;
        END IF;
      END IF;
    END WHILE;

  END LOOP;

  CLOSE tpl_cursor;
END$$

DELIMITER ;

