INSERT INTO `movies` (`id`, `title`, `language`, `genre`, `rating`, `duration`, `description`, `release_date`, `is_now_showing`, `is_upcoming`, `poster_url`, `trailer_url`, `created_at`) VALUES
(1, 'TN 2026', 'Tamil', 'Action', 'UA13+', 250, 'TN 2026 (an initialism for Thanga Natchathiram; transl. Golden Star) is a 2026 Indian Tamil-language political satire film directed by Umapathy S. Ramaiah who wrote the screenplay from a story by his father Thambi Ramaiah. The film stars Natty Subramaniam, M. S. Bhaskar, Thambi Ramaiah and Ilavarasu. It follows the rise of Kulkanth Kumar from a struggling actor to a movie star, and eventually a high-ranking politician. Shot between October 2025, and early 2026, the film was released theatrically on 10 April 2026.', '2026-04-18', 1, 0, 'assets/poster_1776318780_29a70a55.jpg', 'https://youtu.be/9DvVCdE4Prk?si=CMd4_ct8QV5EkilD', '2026-04-16 04:35:19'),
(2, 'Leader', 'Tamil', 'Action', 'UA13+', 216, 'Leader is a 2026 Indian Tamil-language spy action thriller film written and directed by R. S. Durai Senthilkumar and produced by Legend Saravanan. The film stars Saravanan in the lead role alongside Shaam, Andrea Jeremiah, Santhosh Prathap, Payal Rajput, and Iyal in supporting roles. It is the sophomore for Saravanan, both as an actor and producer.', '2026-04-18', 1, 0, 'assets/poster_1776318972_f91f5ae1.jpg', 'https://youtu.be/vSuWyhYlcsM?si=E53kO0x37nZGJQGK', '2026-04-16 04:35:19'),
(3, 'Love Insurance Kompany', 'Tamil', 'Action', 'UA13+', 237, 'Love Insurance Kompany (also known by the acronym LIK; /laɪk/) is a 2026 Indian Tamil-language science fiction romantic comedy film written and directed by Vignesh Shivan. Jointly produced by Rowdy Pictures and Seven Screen Studio, the film stars Pradeep Ranganathan, S. J. Suryah and Krithi Shetty, while Yogi Babu, Seeman, Gouri G Kishan, Shah Ra, Malavika and Sunil Reddy appear in supporting roles. It is set in 2040, where people in love insure their relationships through a dating app named LIK, but a man who believes in organic love, falls in love with a woman embracing tech-driven romance. In doing so, he seeks to challenge LIK.', '2026-04-18', 1, 0, 'assets/poster_1776316582_b9139154.jpg', 'https://youtu.be/wMiCXl8ZybQ?si=qSSYfjzBSNQA6VU3', '2026-04-16 04:35:19'),
(4, 'Lucky Baskhar', 'Tamil', 'Crime/Thriller', 'U', 152, 'A bank officer leads a double life.', '2024-10-31', 0, 1, 'assets/poster_1776505341_e218094e.jpg', '', '2026-04-16 04:35:19'),
(5, 'Thug Life', 'Tamil', 'Action', 'U', 150, 'Upcoming Mani Ratnam directorial.', '2025-06-05', 0, 1, 'assets/poster_1776505328_6e5a444d.jpg', '', '2026-04-16 04:35:19'),
(6, 'Coolie', 'Tamil', 'Action', 'U', 145, 'Rajinikanth in a mass entertainer.', '2025-05-01', 0, 1, 'assets/poster_1776505335_b2816ecc.jpg', '', '2026-04-16 04:35:19');
